  ('social-worker-moex-02627', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於佛洛伊德所提出之人格架構的說明，下列何者錯誤？', '["包括自我、本我、超我三個組成要素", "本我源自於自我，其特徵是非理性、非邏輯、幻想取向", "自我依循現實原則，也就是可以考量現實的狀況來操作的", "超我約在3到5歲時形成，其功能是提供道德指引"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02628', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據Tannen（2005）的觀點，有關不同性別的成年人在溝通時的描述，下列何者錯誤？', '["女性會使用較融洽的交談方式", "女性較喜歡討論個人的生活及感情", "男性較喜歡使用報告式的交談", "男性較容易扮演傾聽者的角色"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02629', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於家庭生命週期的敘述，下列何者錯誤？', '["階段3為「有年輕小孩的家庭」，關鍵發展任務為「系統接納新成員」", "階段4為「有青少年小孩的家庭」，關鍵發展任務為「家庭界線更有彈性」", "階段5為「子女離家與發展」，關鍵發展任務為「接受兩代間的角色轉變」", "處於不同的家庭生命週期階段的夫婦，婚姻的滿意度和挫折感會有所不同"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02630', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於「中年時期」的發展，下列敘述何者錯誤？', '["在態度上，面對所謂「英雄的死亡」，幻想及期待逐漸破滅", "多數婦女的更年期約發生在45到55歲之間，在生理上，面對更年期到來，經驗生心理的變化", "在家庭關係的維繫中，面對「三明治世代」的艱辛與困難", "在認知的發展上，語言及推理的認知能力大不如前"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02631', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '嬰兒有與生俱來的本能，包括天生的「性情（temperament）」，下列關於「性情」的描述何者正確？', '["嬰兒與母親相處時所表現出來的反應稱為「性情」", "嬰兒對環境反應和互動的特定模式稱為「性情」", "「性情」的變化是可以學習的", "嬰兒的語言表達和理解能力可以界定「性情」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02632', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於老人虐待（elder abuse）的敘述，下列何者錯誤？', '["老人虐待最多的是家庭成員，其次才是機構式虐待", "老人虐待的盛行率不易評估，根據衛生福利部的統計，每年大約是1%左右", "提供喘息服務是防止老人虐待的重要方法之一", "因照顧者的無知或失能而拒絕照顧或疏於照顧，也是老人虐待的一種類型"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02633', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於「家庭系統」的陳述，下列何者錯誤？', '["家庭結構是一種經過自身調整與修正而成的互動模式，對整體家庭功能影響重大", "家外支持系統會影響家內夫妻、父母、手足、親子次系統的功能", "家庭成員間的問題被解決就可以代表家庭有發揮功能", "家庭系統內的回饋機制是為了回應環境的變遷，正向或負向都有可能"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02634', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '艾瑞克森（Erikson）主張人格的形成依照固定和井然有序的階段發展而來，下列敘述何者正確？', '["他主張每個發展階段都有必須完成的任務，若未完成會影響到下一個階段的發展", "他主張這些任務完全受到生理驅力的影響", "他主張的人格發展理論乃學習皮亞傑的論述發展而來的", "他主張同性戀的發展是正常化的，社會應予接納"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02635', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於班度拉（Bandura）的社會學習理論主張，下列敘述何者正確？', '["強調角色楷模對人格發展的重要性，例如兒童學到攻擊性行為", "強調學習是對可觀察的環境刺激予以反應，例如害怕毛茸茸的玩具", "強調學習是增強與懲罰的結果，例如給糖滿足愛哭小孩會導致愛哭的頻率增加", "強調適應和組織是學習行為的主要原因"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
